1	type Item = { type: string; enchantment?: number };
2	type Scenario = {
3	  steps: Array<{ op: string; items?: Item[] }>;
4	};
5	
6	const PROCESSING_FEE = 5;
7	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	const BLOCK_OF_3_PRICE = 60;
16	const BLOCK_ELIGIBLE_TYPES = new Set(["rune", "moonstone"]);
17	
18	function quotePremium(items: Item[]): number {
19	  const countsByType: Record<string, number> = {};
20	  for (const item of items) {
21	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
22	  }
23	  let policyBase = 0;
24	  for (const [type, count] of Object.entries(countsByType)) {
25	    if (BLOCK_ELIGIBLE_TYPES.has(type) && count === 3) {
26	      policyBase += BLOCK_OF_3_PRICE;
27	    } else {
28	      policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
29	    }
30	  }
31	  let itemSurcharges = 0;
32	  for (const item of items) {
33	    if ((item.enchantment ?? 0) >= 5) {
34	      itemSurcharges += 0.3 * BASE_PREMIUM_BY_ITEM_TYPE[item.type];
35	    }
36	  }
37	  const firstInsurance = policyBase / 10;
38	  return Math.ceil(policyBase + itemSurcharges + firstInsurance) + PROCESSING_FEE;
39	}
40	
41	export function processScenario(scenario: unknown): unknown {
42	  const { steps } = scenario as Scenario;
43	  const results = steps.map((step) => ({
44	    premium: quotePremium(step.items ?? []),
45	  }));
46	  return { results };
47	}
